                </div>
              </div>
            </div>
            <div className="slice-content">
              <h3>Project One</h3>
              <p className="slice-description">A brief overview of the first vertical slice...</p>
              <details className="slice-details">
                <summary>Read More</summary>
                <p>Detailed description of the project, including technical specifications, challenges overcome, and key features implemented.</p>
              </details>
            </div>
          </div>

          <div className={`slice ${activeSlice === 's2' ? 'activating' : ''}`}>
            <div className="video-preview">
              <div className="video-thumbnail">
                <img src={`${process.env.PUBLIC_URL}/images/project2-thumb.jpg`} alt="Project Two Thumbnail" />
                <button 
                  className="play-overlay" 
                  onMouseOver={() => SFX.play('hover')}
                  onClick={() => {
                    SFX.play('open');
                    setActiveSlice('s2');
                    document.body.style.overflow = 'hidden';
                    document.body.classList.add('modal-open');
                    closeFeaturedGame();
                    closeOthers('video-modal-2');
                    setTimeout(() => document.getElementById('video-modal-2').classList.add('show'), 220);
                  }}
                >
                  <span className="play-icon">▶</span>
                </button>
              </div>
              <div id="video-modal-2" className="video-modal">
                <div className="modal-content" id="vmc-2">
                  <div className="loading-overlay">
                    <div className="loading-spinner"></div>
                    <p>Loading Video...</p>
                  </div>
                  <div className="video-frame">
                  <video
                    controls
                    preload="auto"
                    playsInline
                    poster={`${process.env.PUBLIC_URL}/images/project2-thumb.jpg`}
                    onLoadedData={() => markReady('vmc-2')}
                    onCanPlayThrough={() => markReady('vmc-2')}
                    onWaiting={() => markBuffering('vmc-2')}
                  >
                    <source src={`${process.env.PUBLIC_URL}/videos/project2.mp4`} type="video/mp4" />
